export const getImage = (key) => IMAGE_LIBRARY.find((i) => i.key === key)?.url || null;
export const libraryStats = () => ({
  total: IMAGE_LIBRARY.length,
  delivered: IMAGE_LIBRARY.filter((i) => i.url).length,
});